const _parseWorth = w => {
  const n = parseFloat(w.replace(/[$,+]/g,""));
  const m = /[bB]/.test(w) ? n*1000 : n;
  if (m>=1000) return "$1B+";
  if (m>=500)  return "$500M+";
  if (m>=100)  return "$100M+";
  return "$50M+";
};

